'use client';
import { motion, useAnimationFrame, useMotionValue, useTransform, useScroll, useVelocity, useSpring } from 'framer-motion';
import { useRef } from 'react';
import Link from 'next/link';

function MarqueeItem({ title, slug }: { title: string; slug: string }) {
  return (
    <Link href={`/work/${slug}`} className="block relative group flex-shrink-0 w-[300px] md:w-[400px] aspect-[4/3] mx-4 rounded-xl overflow-hidden">
      <div className="w-full h-full bg-neutral-800 relative">
        {/* Placeholder Gradient */}
        <div className="absolute inset-0 bg-gradient-to-br from-neutral-800 to-neutral-700 transition-transform duration-700 group-hover:scale-105" />
        
        {/* Overlay Content */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-300 bg-black/40 backdrop-blur-[2px]">
          <span className="text-white font-medium text-lg translate-y-4 group-hover:translate-y-0 transition-transform duration-300">
            {title}
          </span>
        </div>
      </div>
    </Link>
  );
}

export default function InfiniteMarquee({ items }: { items: { title: string; slug: string }[] }) {
  const baseX = useMotionValue(0);
  const { scrollY } = useScroll();
  const scrollVelocity = useVelocity(scrollY);
  const smoothVelocity = useSpring(scrollVelocity, {
    damping: 50,
    stiffness: 400
  });
  const velocityFactor = useTransform(smoothVelocity, [0, 1000], [0, 5], {
    clamp: false
  });

  const x = useTransform(baseX, (v) => `${v}%`);
  const directionFactor = useRef<number>(1);

  useAnimationFrame((t, delta) => {
    let moveBy = directionFactor.current * -2 * (delta / 1000); // Base speed

    /**
     * This is what changes the direction of the scroll once we
     * switch scrolling directions.
     */
    if (velocityFactor.get() < 0) {
      directionFactor.current = -1;
    } else if (velocityFactor.get() > 0) {
      directionFactor.current = 1;
    }

    moveBy += directionFactor.current * moveBy * velocityFactor.get();

    baseX.set(baseX.get() + moveBy);
    
    // Infinite loop logic
    // We assume duplicated content width is enough to cover screen
    // Reset when scrolled past -50% (half of duplicated content)
    if (baseX.get() <= -50) {
      baseX.set(0);
    } else if (baseX.get() > 0) {
      baseX.set(-50);
    }
  });

  // Duplicate items 4 times to ensure seamless loop
  const duplicatedItems = [...items, ...items, ...items, ...items];

  return (
    <div className="w-full overflow-hidden py-12">
      <motion.div className="flex w-max" style={{ x }}>
        {duplicatedItems.map((item, idx) => (
          <MarqueeItem key={`${item.slug}-${idx}`} title={item.title} slug={item.slug} />
        ))}
      </motion.div>
    </div>
  );
}
